// Takes 1 item (Airtable GET response) → outputs 1 item per FM market
const records = $input.first().json.records || [];
if (records.length === 0) throw new Error('No previous FM Season records found');

const currentYear = new Date().getFullYear();

return records.map(r => ({
  json: {
    companyIds:  r.fields['Company'] || [],
    contactIds:  r.fields['Contact'] || [],
    yearRound:   !!r.fields['Year Round'],
    marketLabel: (r.fields['Season Name'] || 'Unknown').replace(/[\u2013\u2014-].*$/, '').trim(),
    currentYear
  }
}));

// Runs once per market — pairs new season ID with market context
const seasonId = $input.item.json.records[0].id;
const market   = $('Code: Prep Season Payloads').item.json;

return [{
  json: {
    seasonId,
    ticketSubject: market.currentYear + ' Season Setup - ' + market.marketLabel,
    yearRound:     market.yearRound,
    contactIds:    market.contactIds,
    marketLabel:   market.marketLabel
  }
}];

// Runs once per market — expands to one item per task
const ticketId = $input.item.json.records[0].id;
const ctx      = $('Code: Prep Ticket Payload').item.json;

const taskDefs = ctx.yearRound ? [
  { Task: 'Confirm data plan is active',     Order: 1 },
  { Task: 'Create QB invoice for data plan', Order: 2 }
] : [
  { Task: 'Get market start and end dates from market manager',        Order: 1 },
  { Task: 'Send Remove Hold request to office (email)',                Order: 2 },
  { Task: 'Office confirms hold removed - account open',              Order: 3 },
  { Task: 'Activate data plan in Dejavoo',                             Order: 4 },
  { Task: 'Notify customer - account ready, request test transaction', Order: 5 },
  { Task: 'Confirm test transaction successful',                       Order: 6 },
  { Task: '[POST-SEASON] Confirm all batches closed with customer',    Order: 7 },
  { Task: '[POST-SEASON] Send Close request to office (email)',        Order: 8 },
  { Task: '[POST-SEASON] Office confirms account closed',              Order: 9 },
  { Task: '[POST-SEASON] Deactivate data plan in Dejavoo',             Order: 10 },
  { Task: 'Create QB invoice for data plan',                           Order: 11 }
];

return taskDefs.map(t => ({
  json: {
    task:        t.Task,
    order:       t.Order,
    ticketId,
    seasonId:    ctx.seasonId,
    yearRound:   ctx.yearRound,
    contactIds:  ctx.contactIds,
    marketLabel: ctx.marketLabel
  }
}));

// Read from Expand node — HTTP: Create Task response has no context
const taskItems = $('Code: Expand to Task Items').all();

const seen   = new Set();
const unique = [];

for (const item of taskItems) {
  if (!seen.has(item.json.seasonId)) {
    seen.add(item.json.seasonId);
    unique.push({
      json: {
        seasonId:    item.json.seasonId,
        ticketId:    item.json.ticketId,
        yearRound:   item.json.yearRound,
        contactIds:  item.json.contactIds,
        marketLabel: item.json.marketLabel
      }
    });
  }
}

return unique;

// Read from Dedupe node — HTTP: Link Ticket response has no context
return $('Code: Dedupe Season-Ticket Pairs').all().filter(item =>
  !item.json.yearRound && item.json.contactIds.length > 0
);

// Pairs contact GET response with seasonal market context
const contact = $input.item.json;
const market  = $('Code: Filter Seasonal Markets').item.json;
const formUrl = $('Set: Config').first().json.formUrl;

const email = contact.fields?.Email || null;

if (!email) throw new Error('No email found for ' + market.marketLabel);

return [{ json: { email, marketLabel: market.marketLabel, formUrl } }];

const currentYear = new Date().getFullYear();
const items = $input.all();
const markets = items.map(i => i.json.marketLabel + ' (' + i.json.email + ')').join(', ');
return [{
  json: {
    summary: 'FM Season Annual Creator completed for ' + currentYear + '. Records, tickets, and tasks created for all markets. Date request emails sent to: ' + (markets || 'none') + '.'
  }
}];
